import { useState } from "react";

// ‚îÄ‚îÄ METHODIK & P√ÑDAGOGIK (VerticalKay Education) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
const METHODIK = `VERTICALKAY-METHODIK (verbindlich f√ºr ALLE Stunden):

P√ÑDAGOGIK (Kern):
- INDIREKTE KOMMUNIKATION: Immer Pluralform ("Wir aktivieren...", "Wir strecken..."). NIEMALS einzelne Sch√ºler vorf√ºhren oder mit dem Finger zeigen. Korrekturen √ºber die ganze Gruppe.
- SPIEGEL nutzen: √úber den Spiegel die Gruppe im Blick behalten und korrigieren.
- METAPHERN & BILDSPRACHE: Alltagsvergleiche statt anatomischer Fachsprache.
- REGRESSION f√ºr Schw√§chere (leichtere Variante/Vor√ºbung) + PROGRESSION f√ºr St√§rkere (komplexere Variante) ‚Äì beides immer parallel anbieten.
- 5 LERNTYPEN bedienen: visuell (Spiegel/Demo), auditiv (klare Ansage), lese-schreib (Handout-f√§hige Notiz), kinetisch (selbst ausf√ºhren), solit√§r (Eigentempo).

ANATOMIE & SICHERHEIT:
- LATISSIMUS bei JEDEM Spin und JEDEM H√§ngen aktivieren ("Schultern weg von den Ohren, Schulterbl√§tter Richtung Hosentasche").
- PRESSPOINTS niemals auf Gelenke (Knie, Ellenbogen, Wirbels√§ule) ‚Äì immer auf Muskel/Fleisch.
- BEIDE SEITEN trainieren (Dysbalancen vermeiden) ‚Äì auch wenn's keinen Spa√ü macht.
- KEIN Schwung holen beim Inverten ‚Äì Kraft aus Latissimus + Bauch.
- Pre-Stretch im Warm-Up max. 8 Sekunden halten (sonst Kraftverlust).

R√ÑUMLICHE ORIENTIERUNG (Uhrzeiten):
- 12:00 Uhr = vor der Pole (Spiegel/Publikum)
- 6:00 Uhr = hinter der Pole (Ausgang)
- 3:00 / 9:00 Uhr = seitlich neben der Pole
- "Wir stehen hinter der Pole und stellen uns eine Uhr auf dem Boden vor."

DIDAKTIK:
- Vom BEKANNTEN zum UNBEKANNTEN, vom ALTEN zum NEUEN.
- Figuren 2‚Äì3x pro Seite √ºben, ERST ohne Musik, DANN mit Musik.
- "No rush!" ‚Äì Wiederholung f√ºhrt zum Erfolg, niemals durchhetzen.
- WH = Wiederholung, OST = One Side Turn.`;

// ‚îÄ‚îÄ FIGURENKATALOG ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
function buildCurriculum(level) {
  const l10 = `LEVEL 1.0 (Pre Basic) ‚Äì verf√ºgbare Figuren:
Static Pole: Basic Walk, Position I+II, Pli√©, Hip Circle, Body Wave Up, Pass√©, Body Touch, Pencil Turn/Pirouette, Fan Kick Floor, Fan Kick Pole, Knee Sit, Pull Up (Basic Grip), Heel Sit, Basic Spin, Front Hook Stand, Back Hook, Knee Change, Basic Climb (1x), Prayer Slide Pass√©, Play Leg + OST, Pole Seat Beginner, Lean Back Beginner, Lean Back Single Grip, Headstand Prep.+Hips+Play Leg, Headstand+Candle, Chair Spin Front, Chair Spin+Back Hook, Arch Back, Basic Side Slide, Pin Up Kick, Tic Toc, Hoover, Knee Bridge, Squat Sit, Hip Roll, Wave Up Front/Back
Spinning Pole: Basic Spin Spinning, Back Hook Spinning, Front Hook Spin, Fireman Spin, Mermaid Spin, Side Spin Front/Dizzy Lizzy, Basic Climb Spinning, Chair Spin Spinning, Push Turn, Ballerina Stand, Clock Work, Trucker Girl
Griffarten: Basic Grip/True Grip, Reverse Grip, Safety/Push Grip`;

  const l11 = `\n\nLEVEL 1.1 (Basic/Fundamentals) ‚Äì zus√§tzlich zu 1.0:
Neue Figuren: Basic Spin Back, Chair Spin Back (Reverse Grip), Diamond Spin, Fireman Spin Static, Tuck Spin, Belly Slide, Broken Crucifix Boden+Air, Wrap Around, Lady Seat/Knee Hook Pose, Seat Arm Pit Hold, Basic Invert Open Leg, Lean Back Double Grip, Sunwheel Pose/Stag Pose, Ballerina Pose, Roundabout Pole, Stag Floor, Shoulder Roll, Side Slide, Side Slide Kick
Neue Griffarten: Armpit Hold, Twisted Grip, Reverse Split Grip`;

  const l20 = `\n\nLEVEL 2.0 (Beginner) ‚Äì zus√§tzlich zu 1.0+1.1:
Neue Figuren: Fireman Spin Up, Aerial Pli√© Spin, Sunwheel Spin Front+Back, Attitude Spin, Power Climb (2x), Hook Hold Ext. Leg, Chair Hold Ext. Leg Air, Diagonal Slide, Broken Seat, Stargazer Prep. Safety, Cross Knee Release Safety, Basic Invert Roll Down, Handstand Invert, Inverted Crucifix Release, Handstand Butterfly/Scorpion, Inverted V/Chopper/Helicopter
Neue Griffart: Stronghold`;

  const l30 = `\n\nLEVEL 3.0 (Intermediate) ‚Äì zus√§tzlich zu 1.0+1.1+2.0:
Neue Figuren: Corkscrew Prep., Corkscrew, Tinkerbell Spin, Drama Queen Seat, Martini Seat Floor, Swan Seat, Stargazer (ohne Safety), Cross Knee Release+Handstand, Drama Queen Drop Prep., Invert Play Leg, Invert Ext. Leg, Superman Slide, Outside/Inside Leg Hang Prep., Straddle Pose Push Grip
Neue Griffart: Cup Grip`;

  let c = l10;
  if (level === "1.1") c += l11;
  if (level === "2.0") c += l11 + l20;
  if (level === "3.0") c += l11 + l20 + l30;
  return c + "\n\nLEVEL-REGEL: Verwende AUSSCHLIESSLICH Figuren aus den oben gelisteten Leveln. Niemals h√∂here Figuren einbauen.";
}

// ‚îÄ‚îÄ STUNDENTYP-LOGIK ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
function buildLessonTypeLogic(lessonType) {
  if (lessonType === "Choreographie") {
    return `STUNDENTYP: CHOREOGRAPHIE-AUFBAU
- Die Choreographie wird in 3-4 Teile aufgebaut, pro Einheit kommt 1 Teil dazu.
- Ablauf bei jedem neuen Element:
  1. Figur Schritt f√ºr Schritt OHNE Musik erkl√§ren und 2-3x √ºben
  2. Mit der Choreographie verbinden (alte Teile + neuer Teil), 2x ohne Musik durchgehen
  3. 2x mit Musik tanzen
  4. N√§chste Figur anh√§ngen
- Reihenfolge der Figuren kann frei gestaltet werden, vom Leichten zum Schweren.
- Am Stundenende: ALLE bisher gelernten Teile 2-3x mit Musik durchtanzen.
- Output-Fokus: choreographieTeil + figurenSequenz + musikHinweis`;
  }
  if (lessonType === "Technik") {
    return `STUNDENTYP: TECHNIK-STUNDE
- Reine Technik-Vertiefung, KEINE Choreographie.
- Aufbau: Warm-Up ‚Üí kurze Wiederholung kompletter Choreographie 1x mit Musik ‚Üí dann Technikteil.
- Im Technikteil: Einzelne Figuren technisch sauber durchgehen, jede Figur 4x pro Seite.
- Fokus auf Sauberkeit der Ausf√ºhrung, Automatisierung der Bewegungsabl√§ufe.
- Neue Kombinationen aus bekannten Figuren ausprobieren (z.B. "Basic Spin ‚Üí Front Hook Stand ‚Üí OST").
- Output-Fokus: figurenListe (technisch durchgehen) + neueKombinationen (mit Hinweisen)`;
  }
  return `STUNDENTYP: PRAXIS / WORKSHOP
- Wiederholung und Vertiefung unsicherer Figuren aus den letzten Einheiten.
- ODER: Wenn alles sitzt ‚Üí Workshop-Charakter mit neuen freien Kombinationen aus bekannten Elementen.
- Optional: Eine k√ºrzere zweite Choreographie zum Spielen.
- Es geht um Festigung, nicht um neuen Stoff.
- Output-Fokus: vertiefungsFiguren + freieKombinationen + workshopIdee`;
}

// ‚îÄ‚îÄ WARM-UP-LOGIK (variabel je nach Einheit) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
function buildWarmupGuidance(unit) {
  const u = parseInt(unit, 10);
  let sequenzen = 4;
  if (u >= 2 && u <= 2) sequenzen = 5;
  else if (u >= 3 && u <= 4) sequenzen = 7;
  else if (u >= 5) sequenzen = 6;

  return `WARM-UP-AUFBAU f√ºr Einheit ${u}: ca. 20-25 Min, in ${sequenzen} Sequenzen:
- Sequenz 1: Mobilisation aller Gliedma√üen (oben nach unten: Schultern ‚Üí Arme ‚Üí Kopf ‚Üí Handgelenke ‚Üí Wirbels√§ule ‚Üí H√ºfte ‚Üí Beine)
- Sequenz 2: Cardio + Kraft (HKL anheben, beginnerfreundlich, stehend)
- Sequenz 3: Pre-Stretch an der Pole (max. 8 Sek halten, dynamisch)
- Sequenz 4: Pole-Kraft√ºbungen + Invert-Vor√ºbung${u >= 3 ? "\n- Sequenz 5: Fan Kick Wiederholung (4x rechts, 4x links)" : ""}${sequenzen >= 6 ? "\n- Sequenz " + (sequenzen-1) + ": Wiederholung bekannter Figuren (√úbergang zum Hauptteil)" : ""}${sequenzen === 7 ? "\n- Sequenz 7: Choreographie bis aktueller Stand 1x ohne, 2x mit Musik" : ""}`;
}

